solution_code:
#include <array>
#include <iostream>

struct Point {
    int x {};
    int y {};
};

int manhattanDistance(Point a, Point b) {
    int dx = a.x - b.x;
    if (dx < 0) dx = -dx;
    int dy = a.y - b.y;
    if (dy < 0) dy = -dy;
    return dx + dy;
}

int main() {
    int n {};
    std::cin >> n;
    std::array<Point, 4> pts {};
    for (int i = 0; i < n; ++i) {
        std::cin >> pts[i].x >> pts[i].y;
    }
    Point origin {};
    std::cin >> origin.x >> origin.y;
    for (int i = 0; i < n; ++i) {
        std::cout << "Distance: " << manhattanDistance(pts[i], origin) << '\n';
    }
    return 0;
}
